svg.script:
(function () {
  var svg = document.documentElement;
  svg._chartInit = function (svgEl, ctx) {
var svg       = document.getElementById('root');
  var dataLayerEl = document.getElementById('data-layer');
  var edgeLayer = document.getElementById('edge-layer');
  var nodeLayer = document.getElementById('node-layer');

  /* §2 isDark before all build code */

  /* ── TREE DATA ──────────────────────────────────────────────────────────
     Each node: id, label, sublabel, parentId, colorBranch (palette index 1-6)
     colorBranch propagates down from depth-1 nodes; root uses series-1.
     depth computed automatically during layout.                           */
  var nodes = [
    { id:'ceo',  label:'Chief Product',  sub:'Officer',         parent:null,  branch:1 },

    { id:'eng',  label:'Engineering',    sub:'42 engineers',    parent:'ceo', branch:2 },
    { id:'des',  label:'Design',         sub:'11 designers',    parent:'ceo', branch:3 },
    { id:'dat',  label:'Data & ML',      sub:'18 analysts',     parent:'ceo', branch:4 },

    { id:'fe',   label:'Frontend',       sub:'14 engineers',    parent:'eng', branch:2 },
    { id:'be',   label:'Backend',        sub:'18 engineers',    parent:'eng', branch:2 },
    { id:'infra',label:'Platform',       sub:'10 engineers',    parent:'eng', branch:2 },

    { id:'ux',   label:'UX Research',    sub:'5 researchers',   parent:'des', branch:3 },
    { id:'vis',  label:'Visual Design',  sub:'6 designers',     parent:'des', branch:3 },

    { id:'anal', label:'Analytics',      sub:'8 analysts',      parent:'dat', branch:4 },
    { id:'ml',   label:'ML Eng',         sub:'10 engineers',    parent:'dat', branch:4 },

    { id:'mob',  label:'Mobile',         sub:'7 engineers',     parent:'fe',  branch:2 },
    { id:'web',  label:'Web',            sub:'7 engineers',     parent:'fe',  branch:2 },
    { id:'api',  label:'API',            sub:'9 engineers',     parent:'be',  branch:2 },
  ];

  /* ── BUILD TREE STRUCTURE ──────────────────────────────────────────────*/
  var byId = {};
  nodes.forEach(function(n) { byId[n.id] = n; n.children = []; });
  var root;
  nodes.forEach(function(n) {
    if (n.parent) { byId[n.parent].children.push(n); }
    else { root = n; }
  });

  /* assign depth */
  function setDepth(n, d) { n.depth = d; n.children.forEach(function(c) { setDepth(c, d+1); }); }
  setDepth(root, 0);

  /* ── LAYOUT ─────────────────────────────────────────────────────────────
     Plot area: left=68 right=850 top=100 bottom=500
     Left-to-right: x position by depth, y by vertical rank within depth.  */
  var plotL = 68, plotR = 850, plotT = 100, plotB = 500;
  var nodeW = 100, nodeH = 36;

  var maxDepth = 0;
  nodes.forEach(function(n) { if (n.depth > maxDepth) maxDepth = n.depth; });

  var colW = (plotR - plotL) / (maxDepth + 1);   /* width per depth column */

  /* assign y positions with a post-order layout:
     leaves get evenly spaced slots; parents are centred over their children */
  var leafSlot = 0;
  var totalLeaves = nodes.filter(function(n) { return n.children.length === 0; }).length;
  var slotH = (plotB - plotT) / (totalLeaves + 1);

  function assignY(n) {
    if (n.children.length === 0) {
      leafSlot++;
      n.cy = plotT + leafSlot * slotH;
    } else {
      n.children.forEach(assignY);
      var ys = n.children.map(function(c) { return c.cy; });
      n.cy = (Math.min.apply(null, ys) + Math.max.apply(null, ys)) / 2;
    }
  }
  assignY(root);

  /* x = centre of each depth column */
  nodes.forEach(function(n) {
    n.cx = plotL + (n.depth + 0.5) * colW;
  });

  /* ── COLOUR / DEPTH TINT ─────────────────────────────────────────────────
     §6: tint computed from palette base colour + background, never hardcoded.
     We store the base hex per branch and blend toward bg at each depth.     */

  /* §6 depth-tinting: probe live computed fill from .series-N via getComputedStyle —
     never hardcode hex. This way palette updates and dark-mode swaps propagate
     automatically without maintaining duplicate color maps.                    */
  var bgLight = '#FFFBFE';
  var bgDark  = '#1C1B1F';

  var tintRatio = [1.0, 0.72, 0.48, 0.28];

  var _probe = null;
  function probeColor(cls) {
    if (!_probe) {
      _probe = document.createElementNS('http://www.w3.org/2000/svg', 'rect');
      _probe.style.visibility = 'hidden';
      _probe.style.position   = 'absolute';
      svg.appendChild(_probe);
    }
    _probe.setAttribute('class', cls);
    var fill = window.getComputedStyle(_probe).fill;
    var m = fill.match(/[\d.]+/g);
    return m ? [+m[0], +m[1], +m[2]] : [0, 0, 0];
  }

  function lerp(a, b, t) { return Math.round(a + (b - a) * t); }
  function toHex(v) { return ('0' + v.toString(16)).slice(-2); }

  function blendColor(baseRgb, bgHex, ratio) {
    var bg = (function(h) {
      var n = parseInt(h.replace('#',''), 16);
      return [(n>>16)&255, (n>>8)&255, n&255];
    })(bgHex);
    var r = lerp(bg[0], baseRgb[0], ratio);
    var g = lerp(bg[1], baseRgb[1], ratio);
    var b = lerp(bg[2], baseRgb[2], ratio);
    return '#' + toHex(r) + toHex(g) + toHex(b);
  }

  function getColors(branch, depth) {
    var base  = probeColor('series-' + branch);
    var bg    = svgEl.classList.contains('dark') ? bgDark : bgLight;
    var ratio = tintRatio[depth] !== undefined ? tintRatio[depth] : tintRatio[tintRatio.length-1];
    return {
      fill:   blendColor(base, bg, ratio),
      stroke: blendColor(base, bg, Math.min(1, ratio * 1.4))
    };
  }

  /* recolor() — called on dark-mode toggle; mutates node rect styles in-place */
  function recolor() {
    nodes.forEach(function(n) {
      if (!n._rect) return;
      var c = getColors(n.branch, n.depth);
      n._rect.style.fill   = c.fill;
      n._rect.style.stroke = c.stroke;
    });
  }

  /* ── BUILD DOM ───────────────────────────────────────────────────────────
     §7 paint order: edges first, nodes on top.                             */

  /* count total animated elements for stagger */
  var totalEls = nodes.length + nodes.filter(function(n) { return n.parent; }).length;
  var stagger  = Math.min(0.25, 1.0 / totalEls);

  /* edges */
  var edgeIdx = 0;
  nodes.forEach(function(n) {
    if (!n.parent) return;
    var p = byId[n.parent];

    /* elbow connector: horizontal from parent right edge, vertical, horizontal to child */
    var x1 = p.cx + nodeW / 2;
    var x2 = n.cx - nodeW / 2;
    var mx = (x1 + x2) / 2;
    var y1 = p.cy;
    var y2 = n.cy;

    var edge = document.createElementNS('http://www.w3.org/2000/svg', 'path');
    edge.setAttribute('class', 'edge');
    edge.setAttribute('d', 'M'+x1+','+y1+' H'+mx+' V'+y2+' H'+x2);
    edge.style.animationDelay = (edgeIdx * stagger) + 's';
    edgeLayer.appendChild(edge);
    n._edge = edge;
    edgeIdx++;
  });

  /* nodes */
  var nodeIdx = 0;
  /* stagger nodes after edges complete — offset by edge count */
  var edgeCount = edgeIdx;

  nodes.forEach(function(n) {
    var c  = getColors(n.branch, n.depth);
    var ng = document.createElementNS('http://www.w3.org/2000/svg', 'g');
    ng.setAttribute('class', 'node-g');
    ng.setAttribute('id',    'ng-' + n.id);
    ng.style.animationDelay = (edgeCount * stagger + nodeIdx * stagger) + 's';

    var rx = nodeW / 2, ry = nodeH / 2;
    var nx = n.cx - rx, ny = n.cy - ry;

    /* node rect */
    var rect = document.createElementNS('http://www.w3.org/2000/svg', 'rect');
    rect.setAttribute('x', nx); rect.setAttribute('y', ny);
    rect.setAttribute('width', nodeW); rect.setAttribute('height', nodeH);
    rect.setAttribute('rx', '8');
    rect.setAttribute('class', 'node-rect');
    rect.style.fill   = c.fill;
    rect.style.stroke = c.stroke;
    n._rect = rect;

    /* label */
    var title = document.createElementNS('http://www.w3.org/2000/svg', 'text');
    title.setAttribute('x', n.cx); title.setAttribute('y', n.cy - 6);
    title.setAttribute('text-anchor', 'middle');
    title.setAttribute('class', 'node-title');
    title.textContent = n.label;

    /* sublabel */
    var sub = document.createElementNS('http://www.w3.org/2000/svg', 'text');
    sub.setAttribute('x', n.cx); sub.setAttribute('y', n.cy + 9);
    sub.setAttribute('text-anchor', 'middle');
    sub.setAttribute('class', 'node-sub');
    sub.textContent = n.sub;

    ng.appendChild(rect);
    ng.appendChild(title);
    ng.appendChild(sub);
    nodeLayer.appendChild(ng);
    n._ng = ng;
    nodeIdx++;
  });

  /* ── §3 A1 ANIMATION ──────────────────────────────────────────────────── */
  var lastDelay  = (edgeCount + nodeIdx - 1) * stagger;
  var readyDelay = (lastDelay + 0.8 + 0.1) * 1000;

  requestAnimationFrame(function() {
    requestAnimationFrame(function() {
      Array.prototype.forEach.call(edgeLayer.querySelectorAll('.edge'),     function(el) { el.classList.add('visible'); });
      Array.prototype.forEach.call(nodeLayer.querySelectorAll('.node-g'),   function(el) { el.classList.add('visible'); });
    });
  });

  setTimeout(function() {
    dataLayerEl.classList.add('ready');
    /* Kill the animation so fill-mode:both no longer locks opacity:1 above the CSS cascade.
       .data-layer.ready .node-g / .edge then owns the baseline opacity:1. */
    Array.prototype.forEach.call(edgeLayer.querySelectorAll('.edge'),   function(el) { el.style.animation = 'none'; el.style.opacity = ''; });
    Array.prototype.forEach.call(nodeLayer.querySelectorAll('.node-g'), function(el) { el.style.animation = 'none'; el.style.opacity = ''; });
  }, readyDelay);

  /* ── §5 TOOLTIP ───────────────────────────────────────────────────────── */
  var tipBg  = document.getElementById('tip-bg');
  var tipBdr = document.getElementById('tip-bdr');
  var tipTip = document.getElementById('tip-tip');
  var tipVal = document.getElementById('tip-val');
  var tipLbl = document.getElementById('tip-lbl');

  function showTip(cx, cyTop, cyBot, valTxt, lblTxt) {
    tipVal.textContent = valTxt;
    tipLbl.textContent = lblTxt;
    var pad = 20, bh = 38, rx = 9, tw = 8, tail = 10;
    var hw  = Math.max(tipVal.getBBox().width, tipLbl.getBBox().width) / 2 + pad / 2;
    var tx  = Math.max(hw + 8, Math.min(cx, plotR - hw - 8));
    /* above=true: bubble above node (tail at top edge); below: bubble below (tail at bottom edge) */
    var above = (cyTop - tail - bh - 4) >= plotT;
    var cy = above ? cyTop : cyBot;
    var bT, bB;
    if (above) { bB = cy - tail; bT = bB - bh; }
    else        { bT = cy + tail; bB = bT + bh; }

    tipBg.setAttribute('x', tx - hw); tipBg.setAttribute('y', bT);
    tipBg.setAttribute('width', hw * 2); tipBg.setAttribute('height', bh);

    if (above) {
      tipBdr.setAttribute('d',
        'M'+(tx+tw)+','+bB+' L'+(tx+hw-rx)+','+bB+' Q'+(tx+hw)+','+bB+' '+(tx+hw)+','+(bB-rx)+
        ' L'+(tx+hw)+','+(bT+rx)+' Q'+(tx+hw)+','+bT+' '+(tx+hw-rx)+','+bT+
        ' L'+(tx-hw+rx)+','+bT+' Q'+(tx-hw)+','+bT+' '+(tx-hw)+','+(bT+rx)+
        ' L'+(tx-hw)+','+(bB-rx)+' Q'+(tx-hw)+','+bB+' '+(tx-hw+rx)+','+bB+' L'+(tx-tw)+','+bB);
      tipTip.setAttribute('d', 'M'+(tx-tw)+','+bB+' L'+tx+','+(cy-2)+' L'+(tx+tw)+','+bB);
    } else {
      tipBdr.setAttribute('d',
        'M'+(tx-tw)+','+bT+' L'+(tx-hw+rx)+','+bT+' Q'+(tx-hw)+','+bT+' '+(tx-hw)+','+(bT+rx)+
        ' L'+(tx-hw)+','+(bB-rx)+' Q'+(tx-hw)+','+bB+' '+(tx-hw+rx)+','+bB+
        ' L'+(tx+hw-rx)+','+bB+' Q'+(tx+hw)+','+bB+' '+(tx+hw)+','+(bB-rx)+
        ' L'+(tx+hw)+','+(bT+rx)+' Q'+(tx+hw)+','+bT+' '+(tx+hw-rx)+','+bT+' L'+(tx+tw)+','+bT);
      tipTip.setAttribute('d', 'M'+(tx+tw)+','+bT+' L'+tx+','+(cy+2)+' L'+(tx-tw)+','+bT);
    }
    tipVal.setAttribute('x', tx); tipVal.setAttribute('y', bT + bh * 0.32);
    tipLbl.setAttribute('x', tx); tipLbl.setAttribute('y', bT + bh * 0.72);
    [tipBg, tipBdr, tipTip, tipVal, tipLbl].forEach(function(el) { el.setAttribute('opacity','1'); });
  }

  function hideTip() {
    [tipBg, tipBdr, tipTip, tipVal, tipLbl].forEach(function(el) { el.setAttribute('opacity','0'); });
  }

  /* ── §4 HOVER ──────────────────────────────────────────────────────────
     Highlight the hovered node + its direct parent + direct children.
     Connected edges (to parent and to each child) stay full opacity too.
     Stale-clear on every mouseenter is non-optional.                      */
  var allNodeGs = Array.prototype.slice.call(nodeLayer.querySelectorAll('.node-g'));
  var allEdges  = Array.prototype.slice.call(edgeLayer.querySelectorAll('.edge'));

  nodes.forEach(function(n) {
    var ng = n._ng;
    ng.addEventListener('mouseenter', function() {
      if (!dataLayerEl.classList.contains('ready')) return;

      /* clear stale */
      allNodeGs.forEach(function(el) { el.classList.remove('hovered'); });
      allEdges.forEach(function(el)  { el.classList.remove('hovered'); });
      dataLayerEl.classList.add('hovering');

      /* build connected set: self + parent + children */
      ng.classList.add('hovered');
      if (n.parent && byId[n.parent]._ng) byId[n.parent]._ng.classList.add('hovered');
      n.children.forEach(function(c) { if (c._ng) c._ng.classList.add('hovered'); });

      /* connected edges: edge to my parent + edges to my children */
      if (n._edge) n._edge.classList.add('hovered');
      n.children.forEach(function(c) { if (c._edge) c._edge.classList.add('hovered'); });

      var depthLabel = ['Root','Dept','Team','Sub-team'][n.depth] || 'Depth ' + n.depth;
      showTip(n.cx, n.cy - nodeH / 2, n.cy + nodeH / 2, n.label, depthLabel + ' \u00b7 ' + n.sub);
    });
    ng.addEventListener('mouseleave', function() {
      allNodeGs.forEach(function(el) { el.classList.remove('hovered'); });
      allEdges.forEach(function(el)  { el.classList.remove('hovered'); });
      dataLayerEl.classList.remove('hovering');
      hideTip();
    });
  });

  /* ── §2 DARK MODE ─────────────────────────────────────────────────────── */

  svgEl._onModeChange = function () { recolor(); };
  recolor();
  };
  if (window.bootstrapChart) { window.bootstrapChart(svg); }
}());
